const items = $input.all();

if (!items || items.length === 0) {
  console.log('Nenhum card recebido');
  return [];
}

console.log(`Cards recebidos: ${items.length}`);

// Horário atual em UTC (ms)
const agoraMs = Date.now();
console.log(`Agora UTC: ${new Date(agoraMs).toISOString()}`);

const resultado = [];

for (const item of items) {
  const card = item.json;
  if (!card.due_date || !card.titulo) continue;

  // Parsear due_date de forma robusta (aceita +00:00, Z, sem timezone)
  // Normalizar: remover +00:00 e substituir por Z
  const dueDateStr = String(card.due_date)
    .replace('+00:00', 'Z')
    .replace(' ', 'T');  // "2026-06-05 18:22:00" → "2026-06-05T18:22:00Z"

  const dueDateMs = new Date(dueDateStr).getTime();

  if (isNaN(dueDateMs)) {
    console.log(`Data inválida: ${card.due_date}`);
    continue;
  }

  // Diferença em horas
  const diffHoras = (dueDateMs - agoraMs) / (1000 * 60 * 60);

  console.log(`[${card.titulo.substring(0,40)}] due=${dueDateStr} diff=${diffHoras.toFixed(1)}h`);

  // Janelas de ±2h para cada marco
  const isHoje  = diffHoras >= -2   && diffHoras <= 2;   // ±2h do horário
  const is1dia  = diffHoras >= 22   && diffHoras <= 26;   // ~24h
  const is2dias = diffHoras >= 46   && diffHoras <= 50;   // ~48h

  if (!isHoje && !is1dia && !is2dias) continue;

  // Formatar para horário BRT (UTC-3)
  const dueDateBRT = new Date(dueDateMs - 3 * 60 * 60 * 1000);
  const pad = n => String(n).padStart(2, '0');

  const dataFormatada = dueDateBRT.toLocaleDateString('pt-BR', {
    timeZone: 'UTC',  // já convertemos manualmente
    weekday: 'long',
    day: '2-digit',
    month: 'long',
    year: 'numeric'
  });

  const horaFormatada = `${pad(dueDateBRT.getUTCHours())}:${pad(dueDateBRT.getUTCMinutes())}`;

  const tituloResumido = card.titulo.length > 120
    ? card.titulo.substring(0, 120) + '...'
    : card.titulo;

  let tipoLembrete, emoji, urgencia;
  if (isHoje) {
    tipoLembrete = 'HOJE';
    emoji = '🔨';
    urgencia = 'LEILÃO HOJE! Acesse o link agora.';
  } else if (is1dia) {
    tipoLembrete = '1 DIA';
    emoji = '⚠️';
    urgencia = 'AMANHÃ! Confirme sua participação.';
  } else {
    tipoLembrete = '2 DIAS';
    emoji = '📅';
    urgencia = 'Prepare documentação e análise jurídica!';
  }

  const linhas = [
    `${emoji} *LEMBRETE DE LEILÃO — FALTAM ${tipoLembrete}*`,
    ``,
    `🏠 *Imóvel:*`,
    tituloResumido,
    ``,
    `📆 *Data:* ${dataFormatada}`,
    `🕐 *Horário:* ${horaFormatada}`,
    ``,
    `⚡ ${urgencia}`,
  ];

  if (card.link_leilao) {
    linhas.push(``);
    linhas.push(`🔗 *Link do leilão:*`);
    linhas.push(card.link_leilao);
  }

  linhas.push(``);
  linhas.push(`_FlowDesck · Ruah Systems_`);

  resultado.push({
    json: {
      id: card.id,
      titulo: card.titulo,
      due_date: card.due_date,
      link_leilao: card.link_leilao || '',
      mensagem: linhas.join('\n'),
      tipoLembrete,
      dataFormatada,
      horaFormatada,
      tituloResumido,
      diffHoras: parseFloat(diffHoras.toFixed(2))
    }
  });

  console.log(`✅ Lembrete gerado: ${tipoLembrete} para "${tituloResumido.substring(0,30)}..."`);
}

console.log(`Total lembretes: ${resultado.length}`);
return resultado;
